1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // --- Train the model at startup ---
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
10. 
11. var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(
12.     dataPath, hasHeader: true, separatorChar: ',');
13. 
14. // Map "Yes"/"No" string to boolean Label
15. var labelKeys = new[] { "Yes", "No" };
16. var labelValues = new[] { true, false };
17. var labelMapping = mlContext.Transforms.Conversion.MapValue(
18.     "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
19.     inputColumnName: nameof(ChurnInput.Churned));
20. 
21. var dataWithLabels = labelMapping.Fit(dataView).Transform(dataView);
22. var split = mlContext.Data.TrainTestSplit(dataWithLabels, testFraction: 0.2);
23. 
24. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
25.     .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Age)))
26.     .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Income)))
27.     .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.PurchaseHistory)))
28.     .Append(mlContext.Transforms.Concatenate("Features",
29.         nameof(ChurnInput.Age), nameof(ChurnInput.Income),
30.         "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
31.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());
32. 
33. var model = pipeline.Fit(split.TrainSet);
34. 
35. // Evaluate on held-out test set
36. var predictions = model.Transform(split.TestSet);
37. try
38. {
39.     var metrics = mlContext.BinaryClassification.Evaluate(predictions);
40.     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
41.         $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
42. }
43. catch (ArgumentOutOfRangeException)
44. {
45.     Console.WriteLine("Warning: Test set too small for full evaluation. Add more data for reliable metrics.");
46. }
47. 
48. // Save model and register pooled prediction engine (thread-safe)
49. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
50. mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
51. 
52. builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
53.     .FromFile(modelPath);
54. 
55. var app = builder.Build();
56. 
57. app.MapGet("/", () => "Churn Predictor API — POST /predict");
58. 
59. app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest req) =>
60. {
61.     var input = new ChurnInput
62.     {
63.         Age = req.Age,
64.         Income = req.Income,
65.         Region = req.Region,
66.         PurchaseHistory = req.PurchaseHistory
67.     };
68.     var result = pool.Predict(input);
69.     return Results.Ok(new
70.     {
71.         WillChurn = result.PredictedLabel,
72.         Probability = result.Probability,
73.         Score = result.Score
74.     });
75. });
76. 
77. app.Run();
78. 
79. // --- Data models ---
80. 
81. public class ChurnInput
82. {
83.     [LoadColumn(0)] public float Age { get; set; }
84.     [LoadColumn(1)] public float Income { get; set; }
85.     [LoadColumn(2)] public string Region { get; set; } = "";
86.     [LoadColumn(3)] public float PurchaseHistory { get; set; }
87.     [LoadColumn(4)] public string Churned { get; set; } = "";
88. }
89. 
90. public class ChurnOutput
91. {
92.     [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
93.     public float Probability { get; set; }
94.     public float Score { get; set; }
95. }
96. 
